// src/components/FormPaciente.js
import React, { useState, useEffect } from 'react'
import axios from 'axios'
import { useAuth } from './context/AuthContext' // ajuste o caminho se necessário

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const { user } = useAuth();
  const isAluno = user?.role === 'aluno';

  const [numeroProntuario, setNumeroProntuario] = useState('')
  const [nome, setNome] = useState('')
  const [telefone, setTelefone] = useState('')
  const [mensagemErro, setMensagemErro] = useState('')
  const [formData, setFormData] = useState({
    numero_gaveta: '',
    rg: '',
    cpf: '',
    cep: '',
    data_nascimento: '',
    idade: '',
    endereco: '',
    numero: '',
    cidade: '',
    observacao: ''
  })

  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || '')
      setNome(pacienteEditando.nome || '')
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''))
      setFormData({
        numero_gaveta: pacienteEditando.numero_gaveta || '',
        rg: pacienteEditando.rg || '',
        cpf: pacienteEditando.cpf || '',
        cep: pacienteEditando.cep || '',
        data_nascimento: pacienteEditando.data_nascimento
          ? pacienteEditando.data_nascimento.slice(0, 10)
          : '',
        idade: pacienteEditando.idade || '',
        endereco: pacienteEditando.endereco || '',
        numero: pacienteEditando.numero || '',
        cidade: pacienteEditando.cidade || '',
        observacao: pacienteEditando.observacao || ''
      })
    } else {
      resetForm()
    }
    setMensagemErro('')
  }, [pacienteEditando])

  function resetForm() {
    setNumeroProntuario('')
    setNome('')
    setTelefone('')
    setFormData({
      numero_gaveta: '',
      rg: '',
      cpf: '',
      cep: '',
      data_nascimento: '',
      idade: '',
      endereco: '',
      numero: '',
      cidade: '',
      observacao: ''
    })
  }

  function formatarTelefone(campo) {
    const d = campo.replace(/\D/g, '')
    if (!d) return ''
    if (d.length <= 2) return d.replace(/^(\d{0,2})/, '($1')
    if (d.length <= 6) return d.replace(/^(\d{2})(\d{0,4})/, '($1) $2')
    return d.replace(/^(\d{2})(\d{5})(\d{0,4}).*/, '($1) $2-$3')
  }

  function validarNomeCompleto(valor) {
    const partes = valor.trim().split(/\s+/)
    if (partes.length < 2) return false
    return partes.every(p => p.length >= 2)
  }

  // Checa se já existe paciente com o telefone digitado (exceto se for edição e é o próprio paciente)
  async function telefoneDuplicado(telefone) {
    try {
      const { data } = await axios.get(`/api/pacientes/telefone/${telefone}`);
      if (data && data.id && (!pacienteEditando || data.id !== pacienteEditando.id)) {
        return true;
      }
      return false;
    } catch {
      return false;
    }
  }

  const handleChange = e => {
    const { name, value } = e.target
    setFormData(fd => ({ ...fd, [name]: value }))
  }

  const handleSubmit = async e => {
    e.preventDefault()
    setMensagemErro('')

    // Validação nome (nome e sobrenome)
    if (!validarNomeCompleto(nome)) {
      setMensagemErro('Digite o nome completo (nome e sobrenome, pelo menos 2 letras cada).')
      return
    }

    // Validação telefone (formato)
    const somenteDigitos = telefone.replace(/\D/g, '')
    if (somenteDigitos.length !== 10 && somenteDigitos.length !== 11) {
      setMensagemErro('Telefone inválido. Use 10 ou 11 dígitos.')
      return
    }

    // Validação telefone duplicado
    if (await telefoneDuplicado(somenteDigitos)) {
      setMensagemErro('Já existe um paciente com esse telefone cadastrado.')
      return
    }

    // Monta payload mínimo para aluno
    let dados = {
      nome: nome.trim(),
      telefone: somenteDigitos,
    }
    // Adiciona campos extras se não for aluno
    if (!isAluno) {
      Object.assign(dados, {
        numero_prontuario: numeroProntuario.trim() || null,
        numero_gaveta: formData.numero_gaveta || null,
        rg: formData.rg || null,
        cpf: formData.cpf || null,
        cep: formData.cep || null,
        data_nascimento: formData.data_nascimento || null,
        idade: formData.idade || null,
        endereco: formData.endereco || null,
        numero: formData.numero || null,
        cidade: formData.cidade || null,
        observacao: formData.observacao || null,
      });
    }

    try {
      if (pacienteEditando) {
        await axios.put(`/api/pacientes/${pacienteEditando.id}`, dados)
      } else {
        await axios.post('/api/pacientes', dados)
        resetForm()
        setNome('')
        setTelefone('')
        setNumeroProntuario('')
      }
      setTimeout(() => onNovoPaciente(), 200)
    } catch (err) {
      let msg = 'Erro ao cadastrar/atualizar paciente.'
      if (err.response?.data) {
        if (typeof err.response.data === 'string') {
          msg = err.response.data
        } else if (err.response.data.error) {
          msg = err.response.data.error
        } else if (err.response.data.message) {
          msg = err.response.data.message
        }
      } else if (err.message) {
        msg = err.message
      }
      setMensagemErro(msg)
    }
  }

  return (
    <div className="bg-white mx-auto max-w-auto rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* Nome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome e Sobrenome
          </label>
          <input
            type="text"
            required
            value={nome}
            onChange={e => setNome(e.target.value)}
            className="w-full border rounded px-3 py-2"
          />
        </div>

        {/* Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
          </label>
          <input
            type="tel"
            required
            value={telefone}
            onChange={e => setTelefone(formatarTelefone(e.target.value))}
            placeholder="(XX) XXXXX-XXXX"
            className="w-full border rounded px-3 py-2"
          />
        </div>

        {/* Só mostra campos extras se NÃO for aluno */}
        {!isAluno && (
          <>
            {/* Prontuário / Gaveta */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Número do Prontuário <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  maxLength={8}
                  value={numeroProntuario}
                  onChange={e => setNumeroProntuario(e.target.value)}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Nº Gaveta <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  name="numero_gaveta"
                  value={formData.numero_gaveta}
                  onChange={handleChange}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
            </div>
            {/* RG / CPF */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  RG <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  name="rg"
                  value={formData.rg}
                  onChange={handleChange}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  CPF <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  name="cpf"
                  value={formData.cpf}
                  onChange={handleChange}
                  placeholder="000.000.000-00"
                  className="w-full border rounded px-3 py-2"
                />
              </div>
            </div>
            {/* Nasc. / Idade */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Data de Nascimento <small>(opcional)</small>
                </label>
                <input
                  type="date"
                  name="data_nascimento"
                  value={formData.data_nascimento}
                  onChange={e => setFormData(fd => ({
                    ...fd,
                    data_nascimento: e.target.value,
                    idade: e.target.value ? calcularIdade(e.target.value) : ''
                  }))}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Idade
                </label>
                <input
                  type="number"
                  readOnly
                  name="idade"
                  value={formData.idade}
                  className="w-full bg-gray-100 border rounded px-3 py-2"
                />
              </div>
            </div>
            {/* CEP */}
            <div className="mb-6">
              <label className="block mb-2 font-medium text-gray-700">
                CEP <small>(opcional)</small>
              </label>
              <input
                type="text"
                name="cep"
                value={formData.cep}
                onChange={handleChange}
                onBlur={async () => {
                  const cepLimpo = formData.cep.replace(/\D/g, '')
                  if (cepLimpo.length !== 8) return
                  try {
                    const { data } = await axios.get(`https://viacep.com.br/ws/${cepLimpo}/json/`)
                    if (!data.erro) {
                      setFormData(fd => ({
                        ...fd,
                        endereco: data.logradouro || '',
                        cidade: data.localidade || ''
                      }))
                    }
                  } catch {}
                }}
                placeholder="00000-000"
                className="w-full border rounded px-3 py-2"
              />
            </div>
            {/* Endereço / Nº / Cidade */}
            <div className="mb-6">
              <label className="block mb-2 font-medium text-gray-700">
                Endereço <small>(opcional)</small>
              </label>
              <input
                type="text"
                name="endereco"
                value={formData.endereco}
                onChange={handleChange}
                className="w-full border rounded px-3 py-2"
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Número <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  name="numero"
                  value={formData.numero}
                  onChange={handleChange}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
              <div>
                <label className="block mb-2 font-medium text-gray-700">
                  Cidade <small>(opcional)</small>
                </label>
                <input
                  type="text"
                  name="cidade"
                  value={formData.cidade}
                  onChange={handleChange}
                  className="w-full border rounded px-3 py-2"
                />
              </div>
            </div>
            {/* Observações */}
            <div className="mb-6">
              <label className="block mb-2 font-medium text-gray-700">
                Observações <small>(opcional)</small>
              </label>
              <textarea
                name="observacao"
                value={formData.observacao}
                onChange={handleChange}
                className="w-full border rounded px-3 py-2 h-24"
              />
            </div>
          </>
        )}

        {/* Mensagem de erro somente ao final */}
        {mensagemErro && (
          <div className="mt-4 text-center text-red-600 text-base font-medium">
            {mensagemErro}
          </div>
        )}

        <div className="flex flex-col md:flex-row gap-4 mt-6">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              onClick={onFimEdicao}
              className="bg-[#DA3648] hover:bg-[#BC3140] text-white px-4 py-2 rounded-full"
            >
              Cancelar
            </button>
          )}
        </div>
      </form>
    </div>
  )
}

export default FormPaciente
